4: const std = @import("std");
5: 
6: // ── Data Structures ──────────────────────────────────────────────────
7: 
8: pub const Span = extern struct {
9:     base: u8, // ASCII base letter (a-z, A-Z)
10:     modifier: u8, // 0=none, 'w'=ư/ơ/ă, 'd'=đ, 'a'=â, 'e'=ê, 'o'=ô
11:     tone: u8, // 0=none, 's'=sắc, 'f'=huyền, 'r'=hỏi, 'x'=ngã, 'j'=nặng
12:     flags: u8, // bit 0: is_uppercase, bit 1: is_literal
13: };
14: 
15: pub const State = extern struct {
16:     spans: [16]Span,
17:     len: u8,
18:     mode: u8, // 0=NORMAL, 1=LITERAL
19:     _pad: [2]u8 = .{ 0, 0 },
20: };
