341: // ── Exported API ─────────────────────────────────────────────────────
342: 
343: export fn state_size() usize {
344:     return @sizeOf(State);
345: }
346: 
347: export fn init_state(state: *anyopaque) void {
348:     const s: *State = @ptrCast(@alignCast(state));
349:     s.* = std.mem.zeroes(State);
350: }
351: 
352: export fn reset(state: *anyopaque) void {
353:     const s: *State = @ptrCast(@alignCast(state));
354:     s.* = std.mem.zeroes(State);
355: }
356: 
357: export fn backspace(state: *anyopaque) u8 {
358:     const s: *State = @ptrCast(@alignCast(state));
359:     if (s.len == 0) return 0;
360:     s.len -= 1;
361:     // Clear the removed span
362:     s.spans[s.len] = std.mem.zeroes(Span);
363:     // If all spans removed, reset mode
364:     if (s.len == 0) s.mode = 0;
365:     return 1;
366: }
