534: export fn get_composed_utf16(state: *anyopaque, buf: [*]u16, buf_len: u16) u16 {
535:     const s: *State = @ptrCast(@alignCast(state));
536:     var pos: u16 = 0;
537: 
538:     var i: u8 = 0;
539:     while (i < s.len) : (i += 1) {
540:         if (pos >= buf_len) return 0xFF; // buffer overflow
541: 
542:         const sp = s.spans[i];
543: 
544:         // Literal spans: emit raw base character
545:         if (sp.flags & 0x02 != 0) {
546:             buf[pos] = @intCast(sp.base);
547:             pos += 1;
548:             continue;
549:         }
550: 
551:         const cp = lookupCodepoint(sp.base, sp.modifier, sp.tone);
552:         buf[pos] = cp;
553:         pos += 1;
554:     }
555: 
556:     return pos;
557: }

