246: // ươ auto-fill: if coda added and nucleus has uo/uô, auto-fill w modifier
247: fn autoFillUO(s: *State) void {
248:     const r = computeRegions(s);
249:     if (!r.has_nucleus) return;
250:     if (r.coda_start >= s.len) return; // no coda
251: 
252:     // Look for u and o adjacent in nucleus
253:     var i = r.nucleus_start;
254:     while (i < r.nucleus_end) : (i += 1) {
255:         const cur_lo = toLower(s.spans[i].base);
256:         const next_lo = toLower(s.spans[i + 1].base);
257: 
258:         if (cur_lo == 'u' and next_lo == 'o') {
259:             // If one has 'w' modifier and the other doesn't, auto-fill
260:             const u_has_w = s.spans[i].modifier == 'w';
261:             const o_has_w = s.spans[i + 1].modifier == 'w';
262:             // Also check for ô (modifier 'o')
263:             const o_has_hat = s.spans[i + 1].modifier == 'o';
264: 
265:             if (u_has_w and !o_has_w and !o_has_hat) {
266:                 s.spans[i + 1].modifier = 'w';
267:             } else if (o_has_w and !u_has_w) {
268:                 s.spans[i].modifier = 'w';
269:             } else if (o_has_hat and !u_has_w) {
270:                 // uô → ươ: set w on u, keep ô as is... actually ươ
271:                 // If o has hat (ô), and we want ươ, we need w on both? No.
272:                 // Actually: ươ = u+w, o+w. The hat form uô is separate.
273:                 // Only auto-fill when modifier is 'w'.
274:             }
275:         }
276:     }
